// Worked focus: httpsts-tenant-query-enforcement — Derive tenant from the principal, carry it through repository interfaces, constrain every query and cache key, and test cross-tenant changed cases.
// Evidence: httpsts-worked-http-server-ts-authorization-tenancy-3
// Competency: httpsts-worked-http-server-ts-authorization-tenancy-3.
// Case 5798: privacy-sensitive records API using conditional requests.
// Operating constraint: retain a screen-reader-readable decision trace.
// Changed case: change the tenant and prove denial before repository access.
function worked_http_server_ts_authorization_tenancy_3(subjectTenant: string, resourceTenant: string, action: string, propertyAllowed: boolean): { allowed: boolean; reason: string } {
  if (subjectTenant.length === 0 || subjectTenant !== resourceTenant) {
    return { allowed: false, reason: "tenant-denied" };
  }
  if (action !== "read" && action !== "update") return { allowed: false, reason: "function-denied" };
  if (!propertyAllowed) return { allowed: false, reason: "property-denied" };
  return { allowed: true, reason: "resource-policy" };
}

